game.Players.PlayerAdded:Connect(function(p) p.CharacterAdded:Connect(function(c) task.wait(1) local h = c:WaitForChild("Humanoid") h.WalkSpeed = 100 h.MaxHealth = 500 h.Health = 500 c.ChildAdded:Connect(function(t) if t:IsA("Tool") then t:WaitForChild("Handle").Touched:Connect(function(hit) if hit.Parent:FindFirstChild("Humanoid") then hit.Parent.Humanoid:TakeDamage(50) end end) end end) end) end)
